// Simple HTML escaping
function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

// Simple CSRF token generation (in production, use session-based CSRF)
const csrfSecretKey = crypto.randomBytes(32);
function generateCsrfToken(clientId, state) {
  const data = `${clientId}:${state}:${Date.now()}`;
  const hmac = crypto.createHmac('sha256', csrfSecretKey);
  hmac.update(data);
  const signature = hmac.digest('hex');
  const token = Buffer.from(`${data}:${signature}`).toString('base64url');
  return token;
}

function verifyCsrfToken(token) {
  try {
    const decoded = Buffer.from(token, 'base64url').toString();
    const parts = decoded.split(':');
    if (parts.length < 4) return false;
    const signature = parts.pop();
    const data = parts.join(':');
    const hmac = crypto.createHmac('sha256', csrfSecretKey);
    hmac.update(data);
    const expectedSignature = hmac.digest('hex');
    return safeCompare(signature, expectedSignature);
  } catch {
    return false;
  }
}

