app.post('/token/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Token is required' });
  }

  // Authenticate client
  let authenticatedClientId = null;
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    try {
      const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
      const [headerClientId, headerClientSecret] = decoded.split(':');
      const decodedClientId = decodeURIComponent(headerClientId);
      const decodedClientSecret = decodeURIComponent(headerClientSecret);
      const client = clients.get(decodedClientId);
      if (client && safeCompare(client.client_secret, decodedClientSecret)) {
        authenticatedClientId = decodedClientId;
      }
    } catch {
      // Invalid header
    }
  }

  if (!authenticatedClientId) {
    const { client_id, client_secret } = req.body;
    if (client_id && client_secret) {
      const client = clients.get(client_id);
      if (client && safeCompare(client.client_secret, client_secret)) {
        authenticatedClientId = client_id;
      }
    }
  }

  if (!authenticatedClientId) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  // Revoke the token
  if (tokens.has(token)) {
    const tokenData = tokens.get(token);
    if (tokenData.clientId === authenticatedClientId) {
      tokens.delete(token);
    }
  }

  if (tokens.has(`refresh:${token}`)) {
    const tokenData = tokens.get(`refresh:${token}`);
    if (tokenData.clientId === authenticatedClientId) {
      tokens.delete(`refresh:${token}`);
    }
  }

  // Always return 200 per RFC 7009
  res.status(200).json({});
});

