app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Bearer token required' });
  }

  const accessToken = authHeader.slice(7);
  const tokenData = tokens.get(accessToken);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token not found' });
  }

  if (tokenData.expiresAt < Date.now()) {
    tokens.delete(accessToken);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token has expired' });
  }

  const user = users.get(tokenData.userId);
  if (!user) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'User not found' });
  }

  res.json({
    sub: user.id,
    username: user.username,
    scope: tokenData.scope
  });
});

